CREATE TABLE carts (cart_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(user_id) ON DELETE CASCADE, device_id VARCHAR(255) NOT NULL, restaurant_id UUID REFERENCES restaurants(restaurant_id), status VARCHAR(20) NOT NULL DEFAULT 'active', expires_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE cart_items (cart_item_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), cart_id UUID NOT NULL REFERENCES carts(cart_id) ON DELETE CASCADE, item_id UUID NOT NULL REFERENCES menu_items(item_id), quantity SMALLINT NOT NULL CHECK(quantity>0), customisations JSONB DEFAULT '[]', added_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
